function buildEmailHtml(options) {
  const { subject, headline, bodyHtml, reviewText, reviewerName, ctaText, ctaUrl, urgencyText, previewText } = options;
  return `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>${subject}</title></head><body style="margin:0;padding:0;background-color:#f5f5f0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;"><span style="display:none;max-height:0;overflow:hidden;">${previewText || ''}</span><table width="100%" cellpadding="0" cellspacing="0" style="background:#f5f5f0;"><tr><td align="center" style="padding:20px;"><table width="600" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);"><tr><td style="background:#2D5A27;padding:20px 30px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="color:#ffffff;font-size:20px;font-weight:bold;">TotalGuard Yard Care</td><td align="right" style="color:#ffffff;font-size:14px;"><a href="tel:6085356057" style="color:#ffffff;text-decoration:none;">(608) 535-6057</a></td></tr><tr><td colspan="2" style="color:#C5A55A;font-size:12px;padding-top:4px;">Madison's Most Trusted Yard Care</td></tr></table></td></tr><tr><td style="padding:30px 30px 10px;"><h1 style="margin:0;color:#2D5A27;font-size:24px;">${headline}</h1></td></tr><tr><td style="padding:10px 30px 20px;color:#1a1a1a;font-size:15px;line-height:1.6;">${bodyHtml}</td></tr>${reviewText ? `<tr><td style="padding:0 30px 20px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="background:#f5f5f0;border-left:4px solid #2D5A27;padding:16px 20px;border-radius:0 6px 6px 0;"><div style="color:#C5A55A;font-size:18px;margin-bottom:8px;">★★★★★</div><div style="color:#333;font-style:italic;font-size:14px;margin-bottom:8px;">"${reviewText}"</div><div style="color:#2D5A27;font-weight:bold;font-size:13px;">— ${reviewerName}</div><div style="color:#888;font-size:11px;">Verified Google Review</div></td></tr></table></td></tr>` : ''}${urgencyText ? `<tr><td style="padding:0 30px 20px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="background:#f0f8f0;border:2px solid #2D5A27;border-radius:8px;padding:16px 20px;text-align:center;"><div style="color:#2D5A27;font-weight:bold;font-size:14px;">${urgencyText}</div></td></tr></table></td></tr>` : ''}<tr><td style="padding:0 30px 20px;" align="center"><table cellpadding="0" cellspacing="0"><tr><td style="background:#2D5A27;border-radius:6px;padding:14px 32px;"><a href="${ctaUrl}" style="color:#ffffff;text-decoration:none;font-weight:bold;font-size:16px;display:inline-block;">${ctaText}</a></td></tr></table></td></tr><tr><td style="padding:0 30px 20px;text-align:center;"><div style="color:#555;font-size:13px;">Prefer to talk? <a href="tel:6085356057" style="color:#2D5A27;font-weight:bold;">(608) 535-6057</a></div></td></tr><tr><td style="padding:10px 30px;text-align:center;border-top:1px solid #eee;"><div style="color:#888;font-size:11px;">✓ Licensed & Insured &nbsp; ✓ 4.9★ Google Rating &nbsp; ✓ 500+ Properties &nbsp; ✓ Satisfaction Guaranteed</div></td></tr><tr><td style="background:#1a1a1a;padding:24px 30px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="color:#ffffff;font-size:14px;font-weight:bold;">TotalGuard Yard Care</td></tr><tr><td style="color:#aaa;font-size:12px;padding-top:6px;">7610 Welton Dr, Madison, WI 53711</td></tr><tr><td style="color:#aaa;font-size:12px;padding-top:4px;"><a href="tel:6085356057" style="color:#C5A55A;">(608) 535-6057</a> | <a href="mailto:totalguardllc@gmail.com" style="color:#C5A55A;">totalguardllc@gmail.com</a></td></tr><tr><td style="padding-top:10px;"><a href="https://facebook.com/totalguardyard/" style="color:#C5A55A;font-size:12px;text-decoration:none;margin-right:10px;">Facebook</a> <a href="https://instagram.com/totalguardyardcare" style="color:#C5A55A;font-size:12px;text-decoration:none;margin-right:10px;">Instagram</a> <a href="https://g.page/r/CRW5Dsg2JgwBEBM/review" style="color:#C5A55A;font-size:12px;text-decoration:none;">Google</a></td></tr><tr><td style="color:#666;font-size:10px;padding-top:10px;">Serving Madison, Middleton, Waunakee, Monona, Sun Prairie, Fitchburg, Verona, McFarland, Cottage Grove, DeForest, Oregon & Stoughton</td></tr></table></td></tr></table></td></tr></table></body></html>`;
}

const leads = $('Fetch Active Leads').all().map(i => i.json);
const sentHistory = $('Fetch Sent History').all().map(i => i.json);

// Build dedup set: "email|email_type"
const alreadySent = new Set();
for (const s of sentHistory) {
  if (s.contact_email && s.email_type) {
    alreadySent.add(s.contact_email + '|' + s.email_type);
  }
}

const reviews = {
  hot: { text: 'TotalGuard transformed our yard in just one visit. Professional, on-time, and the results speak for themselves.', name: 'Sarah M., Middleton' },
  warm: { text: 'We tried three other companies before finding TotalGuard. Night and day difference — they actually care about doing it right.', name: 'Mike & Lisa R., Madison' },
  cold: { text: 'Signed up on a whim and now I can\'t imagine using anyone else. My lawn has never looked this good.', name: 'David K., Waunakee' }
};

const results = [];
for (const lead of leads) {
  if (!lead.email) continue;
  const days = Math.floor((Date.now() - new Date(lead.created_at)) / (1000*60*60*24));
  const score = lead.lead_score || 0;
  let tier = score >= 70 ? 'hot' : score >= 40 ? 'warm' : 'cold';
  let sendDay = false;
  if (tier === 'hot' && [1,3,5].includes(days)) sendDay = true;
  if (tier === 'warm' && [2,5,10].includes(days)) sendDay = true;
  if (tier === 'cold' && [3,7,14,30].includes(days)) sendDay = true;
  if (!sendDay) continue;

  const emailType = 'followup_' + tier + '_day' + days;

  // Dedup: skip if already sent this exact email to this lead
  if (alreadySent.has(lead.email + '|' + emailType)) continue;

  const subjects = {
    hot: ['Your TotalGuard quote is ready, ' + lead.first_name, 'Still thinking it over? We saved your spot', 'Final notice: lock in your lawn care rate'],
    warm: ['Madison lawn tips \u2014 from TotalGuard', 'How TotalGuard protects your lawn all season', 'Your neighbors are loving their TotalGuard service'],
    cold: ['Free lawn care tips from TotalGuard', 'Seasonal reminder from TotalGuard Yard Care', 'When you\'re ready, we\'re here']
  };
  const seqIdx = tier === 'hot' ? [1,3,5].indexOf(days) : tier === 'warm' ? [2,5,10].indexOf(days) : [3,7,14,30].indexOf(days);
  const subject = subjects[tier][Math.min(seqIdx, subjects[tier].length-1)];

  const name = lead.first_name || 'there';
  const service = lead.service || 'yard care';
  const review = reviews[tier];

  // Build tier-specific HTML body content
  let bodyHtml = '';
  let headline = '';
  let urgencyText = '';
  let ctaText = 'Get Your Free Quote';
  let previewText = '';

  if (tier === 'hot') {
    headline = seqIdx === 0 ? `Your ${service} quote is ready!` : seqIdx === 1 ? 'We saved your spot' : 'Last chance to lock in your rate';
    previewText = seqIdx === 0 ? `Hi ${name}, your personalized quote for ${service} is ready.` : `Don't miss out on your ${service} quote, ${name}.`;
    bodyHtml = `<p>Hi ${name},</p>` +
      (seqIdx === 0 ? `<p>Thanks for reaching out about <strong>${service}</strong>! We'd love to get your property looking its absolute best.</p><p>As one of Madison's highest-rated yard care companies, we take pride in delivering results that exceed expectations — and we'd love to show you what we can do.</p>` :
       seqIdx === 1 ? `<p>We noticed you haven't booked your <strong>${service}</strong> service yet — no worries! We've saved your spot and your quote is still valid.</p><p>Many of our Madison neighbors book within the first week to lock in seasonal pricing.</p>` :
       `<p>This is your <strong>final reminder</strong> — your personalized quote for <strong>${service}</strong> expires soon. After this, pricing may change based on seasonal demand.</p><p>Lock in today's rate and join 500+ Madison homeowners who trust TotalGuard.</p>`);
    urgencyText = seqIdx === 2 ? '⏰ Quote expires in 48 hours — lock in your rate today!' : '';
    ctaText = seqIdx === 0 ? 'View My Quote' : seqIdx === 1 ? 'Book My Service' : 'Lock In My Rate';
  } else if (tier === 'warm') {
    headline = seqIdx === 0 ? 'Pro lawn tips for Madison homeowners' : seqIdx === 1 ? 'All-season lawn protection' : 'Your neighbors love TotalGuard';
    previewText = `Helpful lawn care tips and insights from TotalGuard, ${name}.`;
    bodyHtml = `<p>Hi ${name},</p>` +
      (seqIdx === 0 ? `<p>Here's a quick lawn care tip from our team: <strong>water deeply 2-3 times per week</strong> rather than lightly every day. Deep watering encourages stronger root growth, which means a healthier, more resilient lawn.</p><p>Want a professional assessment of your yard? We offer free consultations for Madison homeowners.</p>` :
       seqIdx === 1 ? `<p>Madison weather can be unpredictable — from summer heat to heavy rains and everything in between. TotalGuard's seasonal programs keep your lawn protected and thriving all year long.</p><p>Our services include: <strong>weekly mowing, fertilization, aeration, weed control, spring & fall cleanups</strong>, and more.</p>` :
       `<p>More and more of your Madison neighbors are choosing TotalGuard for their yard care needs. With a <strong>4.9-star Google rating</strong> and 500+ properties served, we've become the area's most trusted name in lawn care.</p><p>See what the buzz is about — book a free consultation today.</p>`);
    ctaText = seqIdx === 0 ? 'Get a Free Consultation' : seqIdx === 1 ? 'See Our Services' : 'Join Your Neighbors';
  } else {
    headline = seqIdx === 0 ? 'Free lawn care tips' : seqIdx === 1 ? 'Seasonal yard care reminder' : seqIdx === 2 ? 'Your neighbors trust TotalGuard' : 'We\'re here when you\'re ready';
    previewText = `Lawn care tips and seasonal reminders from TotalGuard Yard Care.`;
    bodyHtml = `<p>Hi ${name},</p>` +
      (seqIdx === 0 ? `<p>Quick tip from the TotalGuard team: <strong>never cut more than 1/3 of your grass blade height</strong> at once. This simple rule keeps your lawn healthier and more resistant to weeds and disease.</p><p>When you're ready for professional care, we're just a call away.</p>` :
       seqIdx === 1 ? `<p>It's a great time to think about your yard! Whether you need a one-time cleanup or ongoing maintenance, TotalGuard has flexible options for every Madison homeowner.</p><p>No contracts required — just great service.</p>` :
       seqIdx === 2 ? `<p>Over 500 Madison-area homeowners trust TotalGuard with their yards. From Middleton to Sun Prairie, we're the local team that shows up on time and gets the job done right.</p>` :
       `<p>No pressure at all — we just wanted you to know that TotalGuard is here whenever you need yard care help. Whether it's next week or next season, we'd love to earn your business.</p><p>Save our number: <strong>(608) 535-6057</strong></p>`);
    ctaText = 'Learn More';
  }

  const htmlBody = buildEmailHtml({
    subject,
    headline,
    bodyHtml,
    reviewText: review.text,
    reviewerName: review.name,
    ctaText,
    ctaUrl: 'https://tgyardcare.com',
    urgencyText: urgencyText || undefined,
    previewText
  });

  results.push({ json: { ...lead, tier, days, subject, emailType, seqStep: seqIdx + 1, htmlBody, body: `Hi ${name},\n\nThanks for your interest in TotalGuard Yard Care! We'd love to get your ${service} looking its best.\n\nBook online at tgyardcare.com or call (608) 535-6057.\n\n- The TotalGuard Team` } });
}
return results;
